1	// ============================================================================
2	// CourtOps Tennis — frontend (single file, vanilla JS, no framework).
3	//
4	// Two areas:
5	//  * Setup — persistent master data (tournaments catalog, sites, officials,
6	//    players, rates, hotels, distances) via generic master-detail CRUD.
7	//  * Tournament workspace — an active tournament (shown in the context bar,
8	//    persisted) scopes Sites / Roster / Assignments / Room blocks / Part B.
9	//
10	// Sections (rough line ranges — search the headers if these drift):
11	//   Theme + small helpers (esc, api, toast, setMsg, confirmDialog, chip)
12	//   Keyboard shortcuts + help modal
13	//   Type-in searchable comboboxes (enhanceSelect / syncCombos)
14	//   Caches + labels + tabs + two-level menu + sizeLists
15	//   Active tournament state (setActive / updateActiveUI)
16	//   GRIDS registry + grid helpers (wireEntity, makeListGrid, makeReadGrid,
17	//     wirePlayerList) — these factories own Tabulator wiring
18	//   Tournament workspace pages (Sites toggle, Roster, Import, Assignments,
19	//     Room blocks, Availability, Inbox + Part B lists, T-shirts, Pairing,
20	//     Doubles, Reports)
21	//   Setup entity configs (tournamentsCrud … distancesCrud)
22	//   CSV export helpers
23	//   FORM_MODALS — wraps workspace add-forms as modal overlays
24	//   ARIA enhancement for every .detail-pane (role=dialog + focus management)
25	//   Auth + role-based views (admin vs official)
26	// ============================================================================
27	
28	// ---- theme (light/dark) — applied ASAP to avoid a flash, persisted locally ----
29	function applyTheme(t) {
30	  const dark = t === "dark";
31	  document.documentElement.setAttribute("data-theme", dark ? "dark" : "light");
32	  try { localStorage.setItem("theme", dark ? "dark" : "light"); } catch (e) { /* ignore */ }
33	  const btn = document.getElementById("theme-toggle");
34	  if (btn) btn.textContent = dark ? "☀ Light" : "🌙 Dark";
35	}
36	applyTheme((() => { try { return localStorage.getItem("theme"); } catch (e) { return null; } })() || "light");
37	document.addEventListener("DOMContentLoaded", () => {
38	  const btn = document.getElementById("theme-toggle");
39	  if (btn) {
40	    applyTheme(document.documentElement.getAttribute("data-theme"));  // sync label
41	    btn.addEventListener("click", () =>
42	      applyTheme(document.documentElement.getAttribute("data-theme") === "dark" ? "light" : "dark"));
43	  }
44	});
