46	let _inflight = 0;
47	function _progress(delta) {
48	  _inflight = Math.max(0, _inflight + delta);
49	  const p = document.getElementById("progress");
50	  if (p) p.classList.toggle("active", _inflight > 0);
51	}
52	// Turn a FastAPI 422 validation `detail` list into something a TD can read.
53	// Each entry is { loc: [...], msg, type } — we keep just the field + msg.
54	function _humanizeDetail(detail, statusText) {
55	  if (typeof detail === "string") return detail;
56	  if (Array.isArray(detail) && detail.length) {
57	    return detail.slice(0, 3).map((d) => {
58	      const field = Array.isArray(d.loc) ? d.loc.filter((p) => p !== "body").join(".") : "";
59	      const msg = d.msg || d.type || "invalid";
60	      return field ? `${field}: ${msg}` : msg;
61	    }).join("; ");
62	  }
63	  if (detail && typeof detail === "object" && detail.msg) return detail.msg;
64	  return statusText || "request failed";
65	}
66	async function api(path, options) {
67	  _progress(1);
68	  try {
69	    const hasBody = options && options.body;
70	    // Only set Content-Type when there's a body, and never on FormData (which
71	    // needs the browser to set the multipart boundary itself).
72	    const headers = hasBody && !(options.body instanceof FormData)
73	      ? { "Content-Type": "application/json" } : {};
74	    const res = await fetch("/api" + path, { ...options, headers: { ...headers, ...(options && options.headers) } });
75	    let body = null;
76	    if (res.status !== 204) {
77	      try { body = await res.json(); }
78	      catch (_) { /* non-JSON error page (HTML 5xx, gateway, etc.) */ }
79	    }
80	    if (!res.ok) {
81	      const detail = body && body.detail !== undefined ? body.detail : res.statusText;
82	      throw new Error(_humanizeDetail(detail, `${res.status} ${res.statusText}`.trim()));
83	    }
84	    return body;
85	  } finally {
86	    _progress(-1);
87	  }
88	}
89	function toast(text, ok = true) {
90	  const box = document.getElementById("toasts");
91	  if (!box || !text) return;
92	  const t = document.createElement("div");
93	  t.className = "toast " + (ok ? "ok" : "bad");
94	  t.setAttribute("role", ok ? "status" : "alert");
95	  t.textContent = text;
96	  box.appendChild(t);
97	  setTimeout(() => { t.style.transition = "opacity .3s"; t.style.opacity = "0"; setTimeout(() => t.remove(), 300); }, ok ? 2500 : 5000);
98	}
99	function setMsg(id, text, ok) {
100	  const el = document.getElementById(id);
101	  if (el) {
102	    el.textContent = text;
103	    el.className = "msg " + (ok ? "ok" : "bad");
104	    el.setAttribute("role", ok ? "status" : "alert");
105	    // Keep error messages visible until the next form interaction; ok messages auto-clear.
106	    if (text && ok !== false) setTimeout(() => { if (el.textContent === text) el.textContent = ""; }, 4000);
107	  }
108	  toast(text, ok);
109	}
