111	// Find the form input most likely responsible for a server error message and
112	// flag it (aria-invalid + .field-error + focus). Errors that don't match any
113	// field name fall back to the form-level message only.
114	function markInvalid(form, errorText) {
115	  if (!form || !errorText) return;
116	  // Strip prior invalid marks before re-evaluating.
117	  for (const el of form.querySelectorAll("[aria-invalid='true']")) {
118	    el.removeAttribute("aria-invalid"); el.classList.remove("field-error");
119	  }
120	  const t = String(errorText).toLowerCase();
121	  // candidates: input/select/textarea with a name
122	  const fields = [...form.elements].filter((e) => e.name);
123	  // word-boundary search: the field name (or its dash/space variants) appears in the error
124	  const hit = fields.find((e) => {
125	    const n = e.name.toLowerCase();
126	    const words = [n, n.replace(/_/g, " "), n.replace(/_/g, "-")];
127	    return words.some((w) => new RegExp("\\b" + w.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "\\b").test(t));
128	  });
129	  if (hit) {
130	    hit.setAttribute("aria-invalid", "true"); hit.classList.add("field-error");
131	    try { hit.focus(); } catch (_) {}
132	  }
133	}
134	// Clear the invalid mark as soon as the user starts editing the flagged field.
135	document.addEventListener("input", (e) => {
136	  const t = e.target;
137	  if (t && t.getAttribute && t.getAttribute("aria-invalid") === "true") {
138	    t.removeAttribute("aria-invalid"); t.classList.remove("field-error");
139	  }
140	}, true);
141	
142	// Styled confirm dialog (replaces native confirm); returns a Promise<bool>.
143	function confirmDialog(message, okLabel = "Delete") {
144	  return new Promise((resolve) => {
145	    const m = document.getElementById("confirm-modal");
146	    const ok = document.getElementById("confirm-ok");
147	    const cancel = document.getElementById("confirm-cancel");
148	    document.getElementById("confirm-text").textContent = message;
149	    ok.textContent = okLabel;
150	    m.hidden = false;
151	    ok.focus();
152	    const done = (v) => {
153	      m.hidden = true;
154	      ok.removeEventListener("click", onOk);
155	      cancel.removeEventListener("click", onCancel);
156	      document.removeEventListener("keydown", onKey);
157	      resolve(v);
158	    };
159	    const onOk = () => done(true);
160	    const onCancel = () => done(false);
161	    const onKey = (e) => { if (e.key === "Escape") done(false); else if (e.key === "Enter") done(true); };
162	    ok.addEventListener("click", onOk);
163	    cancel.addEventListener("click", onCancel);
164	    document.addEventListener("keydown", onKey);
165	  });
166	}
