168	// Keyboard shortcuts: `/` focuses the active panel's filter, `n`/`N` triggers
169	// its + New / + Add button, `?` opens the shortcuts help. Skipped while the
170	// user is typing in a field. Esc-to-close-modal is handled by the detail-pane
171	// MutationObserver block elsewhere.
172	function showShortcuts() {
173	  let m = document.getElementById("shortcuts-modal");
174	  if (!m) {
175	    m = document.createElement("div"); m.id = "shortcuts-modal"; m.className = "modal";
176	    m.innerHTML = `
177	      <div class="modal-box" role="dialog" aria-modal="true" aria-labelledby="shortcuts-title">
178	        <h3 id="shortcuts-title" style="margin-top:0">Keyboard shortcuts</h3>
179	        <table class="shortcuts"><tbody>
180	          <tr><th><kbd>/</kbd></th><td>Focus the page filter</td></tr>
181	          <tr><th><kbd>n</kbd></th><td>Add a new record on the active panel</td></tr>
182	          <tr><th><kbd>1</kbd>-<kbd>9</kbd></th><td>Jump to the Nth tab in the current menu</td></tr>
183	          <tr><th><kbd>Esc</kbd></th><td>Close the open dialog</td></tr>
184	          <tr><th><kbd>?</kbd></th><td>Show this help</td></tr>
185	        </tbody></table>
186	        <div class="actions-row" style="margin-top:0.75rem"><button type="button" id="shortcuts-close">Close</button></div>
187	      </div>`;
188	    document.body.appendChild(m);
189	    const close = () => { m.hidden = true; };
190	    m.querySelector("#shortcuts-close").addEventListener("click", close);
191	    m.addEventListener("click", (e) => { if (e.target === m) close(); });
192	  }
193	  m.hidden = false;
194	  requestAnimationFrame(() => m.querySelector("#shortcuts-close").focus());
195	}
196	const _shortcutsBtn = document.getElementById("shortcuts-btn");
197	if (_shortcutsBtn) _shortcutsBtn.addEventListener("click", showShortcuts);
198	document.addEventListener("keydown", (e) => {
199	  if (e.defaultPrevented) return;
200	  const a = document.activeElement;

200	  const a = document.activeElement;
201	  const inField = a && /^(INPUT|TEXTAREA|SELECT)$/.test(a.tagName) && a.type !== "button";
202	  if (inField) return;
203	  // Skip while a confirm dialog or shortcuts modal is open.
204	  const sm = document.getElementById("shortcuts-modal");
205	  if (sm && !sm.hidden) {
206	    if (e.key === "Escape") { sm.hidden = true; e.preventDefault(); }
207	    return;
208	  }
209	  if (e.ctrlKey || e.metaKey || e.altKey) return;
210	  if (e.key === "/") {
211	    const p = document.querySelector(".panel.active");
212	    const f = p && p.querySelector("input.filter, input[type=search]");
213	    if (f) { e.preventDefault(); f.focus(); f.select(); }
214	  } else if (e.key === "n" || e.key === "N") {
215	    const p = document.querySelector(".panel.active");
216	    const t = p && (p.querySelector(".new-btn:not(.add-trigger)") || p.querySelector(".add-trigger"));
217	    if (t) { e.preventDefault(); t.click(); }
218	  } else if (e.key === "?") {
219	    e.preventDefault(); showShortcuts();
220	  } else if (/^[1-9]$/.test(e.key)) {
221	    // Audit P46: numeric keys jump to the Nth tab in the currently visible
222	    // menu group, giving keyboard parity with mouse tab clicks.
223	    const tabs = [...document.querySelectorAll(".menu .tab")].filter((t) =>
224	      t.offsetParent !== null);  // visible only
225	    const idx = Number(e.key) - 1;
226	    if (tabs[idx]) { e.preventDefault(); tabs[idx].click(); tabs[idx].focus(); }
227	  }
228	});
229	
230	// =================== Division + Event lookup lists ===================
231	// Loaded from the Setup catalog (/api/divisions, /api/events) on init and
232	// refreshed when those CRUDs change. The TD can add/edit/remove rows from the
233	// Setup tabs without a code change — see migration 0027 for the seed data.
234	let divisionsAll = [];
235	let eventsAll = [];
236	
237	function _populateDatalist(id, items) {
238	  const dl = document.getElementById(id);
239	  if (!dl) return;
240	  dl.innerHTML = items.map((it) => {
241	    const value = typeof it === "string" ? it : it.code;
242	    const label = typeof it === "string" ? "" : (it.label === it.code ? "" : it.label);
243	    return `<option value="${esc(value)}"${label ? ` label="${esc(label)}"` : ""}>${esc(label || value)}</option>`;
244	  }).join("");
245	}
246	// Filter divisions / events by tournament type + (optional) player gender.
247	// The catalog rows carry `tournament_type` and `gender` (null = any), so the
248	// rule reduces to: row matches its tournament_type AND (row.gender is null OR
249	// row.gender equals the player's gender OR no gender supplied).
250	function _divisionsFor(type, gender) {
251	  return divisionsAll.filter((d) => d.tournament_type === type
252	    && (d.gender == null || !gender || d.gender === gender));
253	}
254	function _eventsFor(type, gender) {
255	  return eventsAll
256	    .filter((e) => e.tournament_type === type
257	      && (e.gender == null || !gender || e.gender === gender))
258	    .map((e) => e.name);
259	}
260	function refreshDivisionLists(gender) {
261	  // Default to junior when no tournament is active so the form still has
262	  // useful suggestions on first open.
263	  const type = (active && active.type) || "junior";
264	  _populateDatalist("divisions-list", _divisionsFor(type, gender || null));
265	  _populateDatalist("events-list", _eventsFor(type, gender || null));
266	}
267	// When a division/events input gains focus, infer the player gender from the
268	// containing form (player_ref combobox, roster's player_id picker, or the
269	// inline-create gender select) and refresh the shared datalists accordingly.
270	function _inferFormGender(form) {
271	  if (!form || typeof playersById !== "object") return null;
272	  const pref = form.querySelector("[name='player_ref']");
273	  if (pref && pref.value) return (playersById[pref.value] || {}).gender || null;
274	  const picker = form.querySelector("[name='player_id']");
275	  if (picker && picker.value && !picker.disabled) {
276	    return (playersById[picker.value] || {}).gender || null;
277	  }
278	  const newRow = form.querySelector(".roster-new-row [name='gender']");
279	  if (newRow && !newRow.disabled && newRow.value) return newRow.value;
280	  return null;
281	}
282	document.addEventListener("focusin", (e) => {
283	  const t = e.target;
284	  if (!t || t.tagName !== "INPUT") return;
285	  const list = t.getAttribute("list");
286	  if (list !== "divisions-list" && list !== "events-list") return;
287	  refreshDivisionLists(_inferFormGender(t.closest("form")));
288	});
289	
290	// Colored status chip for known tokens (selection status, email status, etc.).
291	const BADGE = {
292	  selected: "ok", alternate: "warn", withdrawn: "bad",
293	  new: "warn", filed: "ok", needs_followup: "warn",
294	  pending: "warn", paired: "ok",
295	  mutual: "info", random: "muted",
296	  same_club: "info", siblings: "info",
297	};
298	function chip(v) {
299	  if (v == null || v === "") return "";
300	  return `<span class="badge badge-${BADGE[v] || "muted"}">${esc(v)}</span>`;
301	}
302	
303	// Open the modal overlay wrapping a workspace add-form (used when filing/editing).
304	function openForm(form) {
305	  if (form && typeof form._openModal === "function") {
306	    // file-from-email sets source_email_id before openForm() — remember the
307	    // filing flow so the modal can route back to the Inbox after close/submit.
308	    form._wasFiling = !!(form.source_email_id && form.source_email_id.value);
309	    form._openModal();
310	    return;
311	  }
312	  if (typeof syncCombos === "function") requestAnimationFrame(syncCombos);
313	}
314	function esc(v) {
315	  if (v === null || v === undefined) return "";
316	  return String(v).replace(/[&<>]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[c]));
317	}
318	function formObj(form) {
319	  const o = {};
320	  for (const el of form.elements) if (el.name) o[el.name] = el.value === "" ? null : el.value;
321	  return o;
322	}
323	// Register a submit handler that preventDefaults and disables the submit button
324	// while the async handler runs (guards against double-submit), re-enabling after.
325	function onSubmit(form, handler) {
326	  form.addEventListener("submit", async (e) => {
327	    e.preventDefault();
328	    const btn = form.querySelector('button[type="submit"]');
329	    // Audit M31: disable the whole form during submit so a user can't edit a
330	    // field after the request is in flight (their next keystroke would land
331	    // on a stale form, then get overwritten when the response renders).
332	    const fieldset = document.createElement("fieldset");
333	    const wasDisabled = [...form.elements].map((el) => el.disabled);
334	    [...form.elements].forEach((el) => (el.disabled = true));
335	    form.classList.add("is-submitting");
336	    try { await handler(e); }
337	    finally {
338	      [...form.elements].forEach((el, i) => (el.disabled = wasDisabled[i]));
339	      form.classList.remove("is-submitting");
340	      if (btn) btn.disabled = false;
341	      fieldset.remove();  // unused now — keeps the original DOM clean
342	    }
343	  });
344	}
345	function fillSelect(el, items, labelFn, none = true) {
346	  if (!el) return;
347	  const cur = el.value;
348	  el.innerHTML = none ? '<option value="">— none —</option>' : "";
349	  for (const it of items) {
350	    const o = document.createElement("option");
351	    o.value = it.id; o.textContent = labelFn(it);
352	    el.appendChild(o);
353	  }
354	  el.value = cur;
355	}
356	
357	// =================== Type-in dropdowns (searchable comboboxes) ===================
358	// Progressively enhance every native <select> into a filterable, type-to-search
359	// dropdown. The native <select> stays in the DOM as the form's source of truth
360	// (value/required/submit/listeners all unchanged) — we just overlay a text input.
361	function enhanceSelect(sel) {
362	  if (!sel || sel.dataset.combo) return;
363	  sel.dataset.combo = "1";
364	  sel.tabIndex = -1;
365	  sel.classList.add("combo-native");
366	  const wrap = document.createElement("span");
367	  wrap.className = "combo";
368	  sel.parentNode.insertBefore(wrap, sel);
369	  wrap.appendChild(sel);
370	  const listId = "combo-list-" + (enhanceSelect._n = (enhanceSelect._n || 0) + 1);
371	  const input = document.createElement("input");
372	  input.type = "text"; input.className = "combo-input"; input.autocomplete = "off";
373	  input.setAttribute("role", "combobox");
374	  input.setAttribute("aria-autocomplete", "list");
375	  input.setAttribute("aria-expanded", "false");
376	  input.setAttribute("aria-haspopup", "listbox");
377	  input.setAttribute("aria-controls", listId);
378	  // Label the overlay input from the wrapping <label>'s leading text (the native
379	  // select is tabindex=-1, so AT reads the input).
380	  const lbl = sel.closest("label");
381	  const lblText = lbl && [...lbl.childNodes].find((n) => n.nodeType === 3 && n.textContent.trim());
382	  input.setAttribute("aria-label",
383	    (sel.getAttribute("aria-label") || (lblText ? lblText.textContent : sel.name) || "select").trim());
384	  const list = document.createElement("div");
385	  list.className = "combo-list"; list.hidden = true; list.id = listId;
386	  list.setAttribute("role", "listbox");
387	  wrap.append(input, list);
388	  let shown = [], hi = -1;
389	
390	  function syncDisplay() {
391	    const o = sel.selectedOptions[0];
392	    const blank = [...sel.options].find((x) => x.value === "");
393	    // A blank/placeholder option becomes the input's grey placeholder (not its
394	    // value), so the field starts empty and you can type a search immediately.
395	    input.placeholder = blank ? blank.textContent : "";
396	    input.value = (o && o.value !== "") ? o.textContent : "";
397	    input.disabled = sel.disabled;
398	  }
399	  function render(q) {
400	    const t = (q || "").trim().toLowerCase();
401	    // The blank/placeholder option (value "") is shown as the input placeholder,
402	    // not as a selectable row. Optional fields are cleared by emptying the text.
403	    shown = [...sel.options].filter((o) => o.value !== "" && (!t || o.textContent.toLowerCase().includes(t)));
404	    list.innerHTML = "";
405	    if (!shown.length) { list.innerHTML = '<div class="combo-empty">No matches</div>'; return; }
406	    shown.forEach((o, i) => {
407	      const it = document.createElement("div");
408	      it.className = "combo-item" + (o.value === sel.value ? " sel" : "") + (i === hi ? " hi" : "");
409	      it.id = listId + "-opt-" + i;
410	      it.setAttribute("role", "option");
411	      it.setAttribute("aria-selected", o.value === sel.value ? "true" : "false");
412	      it.textContent = o.textContent;
413	      it.addEventListener("mousedown", (e) => { e.preventDefault(); choose(o); });
414	      list.appendChild(it);
415	    });
416	  }
417	  function paintHi() {
418	    [...list.children].forEach((c, i) => c.classList.toggle("hi", i === hi));
419	    const cur = list.children[hi];
420	    if (cur) { cur.scrollIntoView({ block: "nearest" }); input.setAttribute("aria-activedescendant", cur.id); }
421	    else input.removeAttribute("aria-activedescendant");
422	  }
423	  function open() { if (sel.disabled) return; render(""); hi = shown.findIndex((o) => o.value === sel.value); paintHi(); list.hidden = false; input.setAttribute("aria-expanded", "true"); }
424	  // commit=true: if the text was cleared, clear the selection (for optional fields
425	  // that have a blank "" option). Otherwise just restore the displayed value.
426	  function close(commit) {
427	    list.hidden = true; hi = -1;
428	    input.setAttribute("aria-expanded", "false");
429	    input.removeAttribute("aria-activedescendant");
430	    if (commit && input.value.trim() === "" && sel.value !== "" && [...sel.options].some((o) => o.value === "")) {
431	      sel.value = ""; sel.dispatchEvent(new Event("change", { bubbles: true }));
432	    }
433	    syncDisplay();
434	  }
435	  function choose(o) { sel.value = o.value; sel.dispatchEvent(new Event("change", { bubbles: true })); syncDisplay(); close(false); }
436	
437	  // Select existing text on focus so the first keystroke overtypes a prior choice.
438	  input.addEventListener("focus", () => { open(); input.select(); });
439	  input.addEventListener("click", open);
440	  input.addEventListener("input", () => { hi = -1; render(input.value); list.hidden = false; input.setAttribute("aria-expanded", "true"); input.removeAttribute("aria-activedescendant"); });
441	  input.addEventListener("keydown", (e) => {
442	    if (e.key === "ArrowDown") { e.preventDefault(); if (list.hidden) return open(); hi = Math.min(shown.length - 1, hi + 1); paintHi(); }
443	    else if (e.key === "ArrowUp") { e.preventDefault(); hi = Math.max(0, hi - 1); paintHi(); }
444	    else if (e.key === "Enter") { if (!list.hidden && shown[hi]) { e.preventDefault(); choose(shown[hi]); } else { e.preventDefault(); close(true); } }
445	    else if (e.key === "Escape") { if (!list.hidden) { e.preventDefault(); close(false); } }
446	  });
447	  document.addEventListener("click", (e) => { if (!wrap.contains(e.target)) close(true); });
448	
449	  // Keep the visible text in sync when options/value/disabled change in code.
450	  new MutationObserver(() => requestAnimationFrame(syncDisplay))
451	    .observe(sel, { childList: true, attributes: true, attributeFilter: ["disabled"] });
452	  sel.addEventListener("change", syncDisplay);
453	  sel._comboSync = syncDisplay;
454	  syncDisplay();
455	}
456	function enhanceAllSelects() { document.querySelectorAll("select").forEach(enhanceSelect); }
