1867	    mount.parentElement.insertBefore(csv, mount);
1868	  }
1869	  let built = false, pending = null, pendingFilter = null;
1870	  const grid = new Tabulator(mount, {
1871	    layout: "fitColumns", maxHeight: opts.maxHeight || "55vh", placeholder,
1872	    renderVertical: "basic",
1873	    columnDefaults: { headerSortTristate: true, resizable: true, tooltip: true, widthGrow: 1 }, columns: _autoHeaderFilters(columns),
