2199	// Map any stored size (full name OR legacy code like "YM") to a canonical code,
2200	// so mixed historical data aggregates into one line; unknowns return as-is.
2201	function shirtCode(v) {
2202	  if (!v) return null;
2203	  const s = String(v).toLowerCase().replace(/[^a-z]/g, "");
2204	  let group, rest;
2205	  if (/^(youth|yth|junior|jr)/.test(s) || (s[0] === "y" && s.length <= 4)) {
2206	    group = "Y"; rest = s.replace(/^(youth|yth|junior|jr|y)/, "");
2207	  } else if (/^adult/.test(s) || (s[0] === "a" && s.length <= 4)) {
2208	    group = "A"; rest = s.replace(/^(adult|a)/, "");
2209	  } else { group = "A"; rest = s; }
2210	  const sz = _SIZE_TOKEN[rest];
2211	  const code = sz && group + sz;
2212	  return _SHIRT_CODES.includes(code) ? code : String(v).trim();
2213	}
