2810	function _csvDownload(matrix, filename) {
2811	  const csv = matrix
2812	    .map((r) => r.map((c) => `"${String(c ?? "").replace(/"/g, '""')}"`).join(","))
2813	    .join("\r\n");
2814	  const url = URL.createObjectURL(new Blob([csv], { type: "text/csv" }));
2815	  const a = document.createElement("a");
2816	  a.href = url; a.download = filename + ".csv"; a.click();
2817	  URL.revokeObjectURL(url);
2818	}
2819	// Visible column headers (skipping the trailing actions/blank column).
2820	function _visibleHeaders(table) {
2821	  const ths = [...table.querySelectorAll("thead th")];
2822	  const keep = ths.map((th) => th.textContent.trim() !== "");
2823	  return { keep, headers: ths.filter((_, i) => keep[i]).map((th) => th.textContent.trim()) };
2824	}
2825	function exportTable(table, name) {
2826	  const { keep, headers } = _visibleHeaders(table);
2827	  const rows = [...table.querySelectorAll("tbody tr")]
2828	    .filter((tr) => !tr.querySelector(".empty"))
2829	    .map((tr) => [...tr.children].filter((_, i) => keep[i]).map((td) => td.textContent.replace(/\s+/g, " ").trim()));
2830	  _csvDownload([headers, ...rows], name);
2831	}
