2893	// Promote every detail-pane to a proper ARIA dialog (role + aria-modal +
2894	// aria-labelledby) and watch the `detail-open` class to focus the first input
2895	// on open and restore focus on close. One pass at load — no per-site changes.
2896	(function _enhanceDetailDialogs() {
2897	  const obs = new MutationObserver((muts) => {
2898	    for (const m of muts) {
2899	      if (m.attributeName !== "class") continue;
2900	      const dlg = m.target;
2901	      const opening = dlg.classList.contains("detail-open");
2902	      const wasOpen = m.oldValue && m.oldValue.split(/\s+/).includes("detail-open");
2903	      if (opening && !wasOpen) {
2904	        dlg._prevFocus = document.activeElement;
2905	        requestAnimationFrame(() => {
2906	          // Prefer the first form field over the close button (querySelector
2907	          // picks by DOM order, so a multi-query gets us field-first).
2908	          const f = dlg.querySelector('input:not([type="hidden"]):not([disabled]), select:not([disabled]), textarea:not([disabled])')
2909	            || dlg.querySelector('button:not([disabled])');
2910	          if (f) try { f.focus(); } catch (_) {}
2911	        });
2912	      } else if (!opening && wasOpen && dlg._prevFocus && typeof dlg._prevFocus.focus === "function") {
2913	        try { dlg._prevFocus.focus(); } catch (_) {}
2914	      }
2915	    }
2916	  });
2917	  for (const dlg of document.querySelectorAll(".detail-pane")) {
2918	    if (!dlg.hasAttribute("role")) {
2919	      dlg.setAttribute("role", "dialog");
2920	      dlg.setAttribute("aria-modal", "true");
2921	      const title = dlg.querySelector(".detail-title");
2922	      if (title) {
2923	        if (!title.id) title.id = "dlg-" + Math.random().toString(36).slice(2, 8);
2924	        dlg.setAttribute("aria-labelledby", title.id);
2925	      }
2926	    }
2927	    obs.observe(dlg, { attributes: true, attributeOldValue: true, attributeFilter: ["class"] });
2928	  }
2929	})();
